#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume the newline after T
    while (T--) {
        char line[320];
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        int present[26] = {0};
        for (int i = 0; line[i]; ++i) {
            if (isalpha((unsigned char)line[i])) {
                int idx = tolower((unsigned char)line[i]) - 'a';
                present[idx] = 1;
            }
        }
        int found = 0;
        for (int i = 0; i < 26; ++i) {
            if (!present[i]) {
                putchar('a' + i);
                putchar('\n');
                found = 1;
                break;
            }
        }
        if (!found) {
            puts("~");
        }
    }
    return 0;
}

