import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0])
    out_lines = []
    for i in range(1, T + 1):
        line = data[i]
        present = [False] * 26
        for ch in line:
            if ch.isalpha():
                present[ord(ch.lower()) - ord('a')] = True
        for idx in range(26):
            if not present[idx]:
                out_lines.append(chr(ord('a') + idx))
                break
        else:
            out_lines.append('~')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

