const T = parseInt(input[idx++].trim(), 10);
let result = [];
for (let t = 0; t < T; ++t) {
    const line = (input[idx++] || '').trimEnd();
    const present = new Array(26).fill(false);
    for (let ch of line) {
        const code = ch.charCodeAt(0);
        if ((code >= 65 && code <= 90) || (code >= 97 && code <= 122)) {
            const lower = ch.toLowerCase();
            present[lower.charCodeAt(0) - 97] = true;
        }
    }
    let found = false;
    for (let i = 0; i < 26; ++i) {
        if (!present[i]) {
            result.push(String.fromCharCode(97 + i));
            found = true;
            break;
        }
    }
    if (!found) result.push('~');
}
